Hash256 sha256(const Byte* d,std::size_t n){ std::vector<Byte> m(d,d+n); auto bits=static_cast<std::uint64_t>(n)*8; m.push_back(0x80); while(m.size()%64!=56)m.push_back(0); for(int i=7;i>=0;--i)m.push_back(Byte(bits>>(i*8))); std::uint32_t h[8]={0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19}; for(size_t o=0;o<m.size();o+=64){std::uint32_t w[64]; for(int i=0;i<16;++i)w[i]=(m[o+4*i]<<24)|(m[o+4*i+1]<<16)|(m[o+4*i+2]<<8)|m[o+4*i+3]; for(int i=16;i<64;++i){auto s0=R(w[i-15],7)^R(w[i-15],18)^(w[i-15]>>3);auto s1=R(w[i-2],17)^R(w[i-2],19)^(w[i-2]>>10);w[i]=w[i-16]+s0+w[i-7]+s1;} auto a=h[0],b=h[1],c=h[2],e=h[4],f=h[5],g=h[6],hh=h[7],dd=h[3]; for(int i=0;i<64;++i){auto S1=R(e,6)^R(e,11)^R(e,25);auto ch=(e&f)^((~e)&g);auto t1=hh+S1+ch+K[i]+w[i];auto S0=R(a,2)^R(a,13)^R(a,22);auto maj=(a&b)^(a&c)^(b&c);auto t2=S0+maj;hh=g;g=f;f=e;e=dd+t1;dd=c;c=b;b=a;a=t1+t2;} h[0]+=a;h[1]+=b;h[2]+=c;h[3]+=dd;h[4]+=e;h[5]+=f;h[6]+=g;h[7]+=hh;} Hash256 out{};for(int i=0;i<8;++i)for(int j=0;j<4;++j)out[4*i+j]=Byte(h[i]>>(24-8*j));return out;}
Hash256 sha256(const std::string&s){return sha256(reinterpret_cast<const Byte*>(s.data()),s.size());}
std::string hex(const Hash256& h){static const char*x="0123456789abcdef";std::string s;s.reserve(64);for(auto b:h){s+=x[b>>4];s+=x[b&15];}return s;} bool from_hex(const std::string&s,Hash256&o){if(s.size()!=64)return false;auto v=[](char c)->int{if(c>='0'&&c<='9')return c-'0';if(c>='a'&&c<='f')return c-'a'+10;if(c>='A'&&c<='F')return c-'A'+10;return-1;};for(int i=0;i<32;++i){int a=v(s[2*i]),b=v(s[2*i+1]);if(a<0||b<0)return false;o[i]=Byte((a<<4)|b);}return true;}
